export async function createBrowserProvider() {
  if (typeof window === "undefined" || !window.ethereum) {
    throw new Error("No injected wallet found");
  }
  return new ethers.BrowserProvider(window.ethereum);
}

export async function connectWallet() {
  const provider = await createBrowserProvider();
  await provider.send("eth_requestAccounts", []);
  const signer = await provider.getSigner();
  return {
    provider,
    signer,
    address: await signer.getAddress(),
    network: await provider.getNetwork()
  };
}

export async function createSwapDApp({ routerAddress, chainId }) {
  const provider = await createBrowserProvider();
  await provider.send("eth_requestAccounts", []);
  const dapp = new TokenSwapDApp({ provider, routerAddress, chainId });
  const address = await dapp.connect();
  return { dapp, address };
}

